Rule.Source:
   
  import org.apache.commons.logging.Log;
  import org.apache.commons.logging.LogFactory;

  import sailpoint.object.ProvisioningPlan;
  import sailpoint.object.Identity;
  import sailpoint.object.ProvisioningPlan.AccountRequest;
  import sailpoint.object.ProvisioningPlan.AttributeRequest;
  import sailpoint.object.ProvisioningPlan.ObjectOperation;

  Log loggerObj = LogFactory.getLog("ascension.sailpoint.rule.ssm");

  //loggerObj.debug("Ascension-Rule-SSM-BeforeRule-AddEntitlement - Start..") ; 

  String 	APP_NAME_SURGERY_SCHEDULING_MANAGER 		= "Surgery Scheduling Manager" ;

  Map userInfoPublishEventInfoMap = new HashMap() ; 

  String selectedIdentityName = "" ;

  void logInputs(){

    loggerObj.debug("Ascension-Rule-SSM-BeforeRule-AddEntitlement - context - " + context) ; 

    loggerObj.debug("Ascension-Rule-SSM-BeforeRule-AddEntitlement - application - " + application) ;

    loggerObj.debug("Ascension-Rule-SSM-BeforeRule-AddEntitlement - requestEndPoint - " + requestEndPoint) ;

    loggerObj.debug("Ascension-Rule-SSM-BeforeRule-AddEntitlement - oldResponseMap - " + oldResponseMap) ;

    loggerObj.debug("Ascension-Rule-SSM-BeforeRule-AddEntitlement - restClient - " + restClient) ;

    loggerObj.debug("Ascension-Rule-SSM-BeforeRule-AddEntitlement - provisioningPlan - " + provisioningPlan) ;  

  }	



  void extractProvisioningData(){

    loggerObj.debug("Ascension-Rule-SSM-BeforeRule-AddEntitlement - extractProvisioningData() - Start...") ;

    try {

      if(provisioningPlan!=null){

        loggerObj.debug("Ascension-Rule-SSM-BeforeRule-AddEntitlement - extractProvisioningData() - Provisioning Plan - " + provisioningPlan.toXml()) ;	

        selectedIdentityName = provisioningPlan.getNativeIdentity() ;

        loggerObj.debug("Ascension-Rule-SSM-BeforeRule-AddEntitlement - extractProvisioningData() - Provisioning Plan - Native Identity - " + selectedIdentityName) ;

        Identity selectedIdentity = context.getObjectByName(Identity.class,selectedIdentityName) ;

        String email = "" ;

        if(selectedIdentity.getEmail()!=null){

          email = selectedIdentity.getEmail() ; 
        } 

        loggerObj.debug("Ascension-Rule-SSM-BeforeRule-AddEntitlement - extractProvisioningData() - Provisioning Plan - Email - " + email) ;

        /*
			 	IdentityService identityService = new IdentityService(context) ; 

			 	List aDLinks = identityService.getLinks(selectedIdentity, "AD-DS") ;

			 	for(List applicationLinks: aDLinks){


			 	} */


        List accountRequests = provisioningPlan.getAccountRequests(APP_NAME_SURGERY_SCHEDULING_MANAGER) ; 

        for(AccountRequest accountRequest: accountRequests) {

          String applicationName = accountRequest.getApplication() ; 
          String operation = accountRequest.getOp().toString() ;

          loggerObj.debug("Ascension-Rule-SSM-BeforeRule-AddEntitlement - extractProvisioningData() - Provisioning Plan - applicationName - " + applicationName) ;
          loggerObj.debug("Ascension-Rule-SSM-BeforeRule-AddEntitlement - extractProvisioningData() - Provisioning Plan - operation - " + operation) ;	

          List attributeRequests = accountRequest.getAttributeRequests() ;

          for(AttributeRequest attributeRequest: attributeRequests) {

            String attributeRequestName = attributeRequest.getName() ; 

            String attributeRequestOp = attributeRequest.getOp().toString() ;

            String attributeRequestValue = null ;

            if(attributeRequest.getValue()!=null) {

              attributeRequestValue = (String) attributeRequest.getValue() ; 
            }

            loggerObj.debug("Ascension-Rule-SSM-BeforeRule-AddEntitlement - extractProvisioningData() - Provisioning Plan - attributeRequestName - " + attributeRequestName) ;
            loggerObj.debug("Ascension-Rule-SSM-BeforeRule-AddEntitlement - extractProvisioningData() - Provisioning Plan - attributeRequestOp - " + attributeRequestOp) ;	
            loggerObj.debug("Ascension-Rule-SSM-BeforeRule-AddEntitlement - extractProvisioningData() - Provisioning Plan - attributeRequestValue - " + attributeRequestValue) ;

            // TODO Define in constant file.

            if(attributeRequestName.equalsIgnoreCase("Username")){

              //userInfoPublishEventInfoMap.put("username",attributeRequestValue) ; 

              userInfoPublishEventInfoMap.put("username",selectedIdentityName) ; 

            } else if(attributeRequestName.equalsIgnoreCase("Roles")){

              userInfoPublishEventInfoMap.put("adGroups",attributeRequestValue) ;
              
              userInfoPublishEventInfoMap.put("adGroupsOperation",attributeRequestOp) ;

            } else if(attributeRequestName.equalsIgnoreCase("Domain")){

              userInfoPublishEventInfoMap.put("Domain",attributeRequestValue) ;

            } else if(attributeRequestName.equalsIgnoreCase("Email")){

              //userInfoPublishEventInfoMap.put("Email",attributeRequestValue) ;

              userInfoPublishEventInfoMap.put("Email",email) ;
              
            } else if(attributeRequestName.equalsIgnoreCase("Practice")){

              //userInfoPublishEventInfoMap.put("Email",attributeRequestValue) ;
			  
			  String practiceID = "" ;
			  
			  if(attributeRequestValue!=null && !attributeRequestValue.isEmpty()){
			  	
			  	practiceID = attributeRequestValue.split(" - ")[0] ;
			  }
              userInfoPublishEventInfoMap.put("Practice_ID",practiceID) ;
              
            }
          }

          accountRequest.setNativeIdentity(selectedIdentityName) ; 
        }

        loggerObj.debug("Ascension-Rule-SSM-BeforeRule-AddEntitlement - extractProvisioningData() - userInfoPublishEventInfoMap - " + userInfoPublishEventInfoMap) ;
      }
    } catch (Exception exception){

      loggerObj.error("Ascension-Rule-SSM-BeforeRule-AddEntitlement - extractProvisioningData() - Exception occured while extracting Provisioning data - " + exception.getMessage()) ;  		
    }

    loggerObj.debug("Ascension-Rule-SSM-BeforeRule-AddEntitlement - extractProvisioningData() - End.") ;
  }

  logInputs() ; 

  extractProvisioningData() ;

  if(!userInfoPublishEventInfoMap.isEmpty()){

    String userInfoPublishEventMessageID = publishUserInfoNotificationMessage(userInfoPublishEventInfoMap, userInfoPublishEventInfoMap.get("adGroupsOperation")) ;

    loggerObj.info("Ascension-Rule-SSM-BeforeRule-AddEntitlement - userInfoPublishEventMessageID - " + userInfoPublishEventMessageID) ;
    
    if(userInfoPublishEventMessageID!=null && !userInfoPublishEventMessageID.isEmpty()){
	    ProvisioningPlan adPlan = prepareADPlan(provisioningPlan,
	    										getADGroupDN(userInfoPublishEventInfoMap.get("adGroups")),
	    										userInfoPublishEventInfoMap.get("adGroupsOperation"),
	    										userInfoPublishEventInfoMap.get("Practice_ID"),
	    										"Set"
	    										) ; 
	    initiateLCMProvisioningBP(userInfoPublishEventInfoMap.get("username"), adPlan, userInfoPublishEventMessageID) ; 
	    
	    loggerObj.info("Ascension-Rule-SSM-BeforeRule-AddEntitlement - Successfully Launched LCM WorkFlow") ;
	    
	  }     
    }

  //requestEndPoint.setResMappingObj(java.util.Collections.singletonMap("userName",selectedIdentityName)) ; 

  loggerObj.debug("Ascension-Rule-SSM-BeforeRule-AddEntitlement - End.") ;
